css:
.heart-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 40px; height: 40px;
  border: none; background: none;
  cursor: pointer;
  font-size: 22px;
  transition: transform 0.15s ease;
}
.heart-btn:hover { transform: scale(1.15); }
.heart-btn.active { animation: heart-pop 0.4s cubic-bezier(0.34,1.56,0.64,1); }
@keyframes heart-pop {
  0% { transform: scale(1); }
  40% { transform: scale(1.4); }
  70% { transform: scale(0.9); }
  100% { transform: scale(1); }
}

.pop-toggle { position: relative; width: 52px; height: 28px; cursor: pointer; }
.pop-toggle input { display: none; }
.pop-track {
  position: absolute; inset: 0;
  border-radius: 50px;
  background: rgba(255,255,255,0.1);
  border: 1px solid rgba(255,255,255,0.15);
  transition: background 0.3s ease;
}
.pop-thumb {
  position: absolute;
  width: 20px; height: 20px;
  top: 3px; left: 3px;
  background: rgba(255,255,255,0.6);
  border-radius: 50%;
  transition: all 0.3s cubic-bezier(0.34,1.56,0.64,1);
}
.pop-toggle input:checked ~ .pop-track { background: #B8FB3C; }
.pop-toggle input:checked ~ .pop-thumb { transform: translateX(24px); background: #0a0a0f; }

.pop-check input:checked ~ .check-box {
  background: #B8FB3C;
  border-color: #B8FB3C;
  animation: check-spring 0.4s cubic-bezier(0.34,1.56,0.64,1);
}
@keyframes check-spring {
  0% { transform: scale(0.6); }
  60% { transform: scale(1.15); }
  100% { transform: scale(1); }
}

.bell-btn {
  display: inline-flex;
  font-size: 24px;
  cursor: pointer;
  border: none; background: none;
  transform-origin: top center;
}
.bell-btn:hover { animation: bell-ring 0.5s ease; }
@keyframes bell-ring {
  0%, 100% { transform: rotate(0deg); }
  10%, 50% { transform: rotate(12deg); }
  30%, 70% { transform: rotate(-12deg); }
  90% { transform: rotate(4deg); }
}

.progress-micro { height: 4px; background: rgba(255,255,255,0.1); border-radius: 2px; overflow: hidden; }
.progress-micro .bar {
  height: 100%;
  background: linear-gradient(to right, #B8FB3C, #06b6d4);
  border-radius: 2px;
  width: 0;
  transition: width 1s cubic-bezier(0.4,0,0.2,1);
}
.progress-micro.active .bar { width: 75%; }

.ripple-btn {
  position: relative;
  overflow: hidden;
  cursor: pointer;
  padding: 10px 24px;
  border-radius: 8px;
  border: none;
  background: #B8FB3C;
  color: #0a0a0f;
  font-weight: 600;
}
.ripple-btn .ripple {
  position: absolute;
  border-radius: 50%;
  background: rgba(0,0,0,0.2);
  transform: scale(0);
  animation: btn-ripple 0.6s linear;
  pointer-events: none;
}
@keyframes btn-ripple { to { transform: scale(4); opacity: 0; } }

.tooltip-container { position: relative; display: inline-block; }
.tooltip-pop {
  position: absolute;
  bottom: calc(100% + 8px);
  left: 50%;
  transform: translateX(-50%) scale(0.8);
  transform-origin: bottom center;
  background: rgba(255,255,255,0.1);
  backdrop-filter: blur(10px);
  border: 1px solid rgba(255,255,255,0.2);
  border-radius: 8px;
  padding: 6px 12px;
  color: #fff;
  font-size: 12px;
  white-space: nowrap;
  pointer-events: none;
  opacity: 0;
  transition: all 0.2s cubic-bezier(0.34,1.56,0.64,1);
}
.tooltip-container:hover .tooltip-pop { opacity: 1; transform: translateX(-50%) scale(1); }

.tab-bar {
  position: relative;
  display: flex;
  background: rgba(255,255,255,0.04);
  border-radius: 10px;
  padding: 4px;
}
.tab-item {
  position: relative; z-index: 1;
  padding: 7px 16px;
  font-size: 13px;
  font-weight: 500;
  color: rgba(255,255,255,0.4);
  border-radius: 7px;
  cursor: pointer;
  transition: color 0.2s ease;
}
.tab-item.active { color: #0a0a0f; }
.tab-indicator {
  position: absolute; top: 4px;
  height: calc(100% - 8px);
  background: #B8FB3C;
  border-radius: 7px;
  transition: all 0.3s cubic-bezier(0.4,0,0.2,1);
  z-index: 0;
}

.count-up-num {
  font-size: 48px;
  font-weight: 800;
  display: inline-block;
  animation: count-appear 0.5s ease forwards;
}
@keyframes count-appear {
  from { transform: translateY(20px); opacity: 0; }
  to { transform: translateY(0); opacity: 1; }
}
/* JS: increment number from 0 to target over duration */

.copy-btn {
  position: relative;
  padding: 8px 16px;
  border-radius: 8px;
  background: rgba(255,255,255,0.08);
  border: 1px solid rgba(255,255,255,0.15);
  color: rgba(255,255,255,0.7);
  font-size: 13px;
  cursor: pointer;
  transition: all 0.2s ease;
}
.copy-btn.copied {
  background: rgba(184,251,60,0.1);
  border-color: rgba(184,251,60,0.3);
  color: #B8FB3C;
  animation: confirm-pop 0.3s ease;
}
@keyframes confirm-pop {
  0% { transform: scale(0.95); }
  50% { transform: scale(1.05); }
  100% { transform: scale(1); }
}

.star-rating { display: flex; gap: 4px; cursor: pointer; }
.star {
  font-size: 22px;
  color: rgba(255,255,255,0.15);
  transition: color 0.15s ease, transform 0.15s ease;
}
.star-rating:hover .star { color: #fbbf24; }
.star-rating .star:hover ~ .star { color: rgba(255,255,255,0.15); }
.star:hover { transform: scale(1.2); }

.drag-item {
  cursor: grab;
  user-select: none;
  transition: all 0.2s ease;
}
.drag-item:active {
  cursor: grabbing;
  transform: scale(1.03) rotate(1deg);
  box-shadow: 0 12px 40px rgba(0,0,0,0.3);
  z-index: 100;
}

.badge-pulse { position: relative; display: inline-flex; align-items: center; justify-content: center; }
.badge-num {
  background: #ef4444;
  color: #fff;
  border-radius: 50%;
  width: 20px; height: 20px;
  font-size: 11px;
  font-weight: 700;
  display: flex; align-items: center; justify-content: center;
}
.badge-num::after {
  content: '';
  position: absolute;
  border-radius: 50%;
  background: rgba(239,68,68,0.4);
  width: 20px; height: 20px;
  animation: badge-ring 1.5s ease-out infinite;
}
@keyframes badge-ring {
  0% { transform: scale(1); opacity: 1; }
  100% { transform: scale(2.5); opacity: 0; }
}

.input-error {
  animation: error-shake 0.4s ease;
  border-color: #ef4444 !important;
  box-shadow: 0 0 0 3px rgba(239,68,68,0.15) !important;
}
@keyframes error-shake {
  0%, 100% { transform: translateX(0); }
  20% { transform: translateX(-6px); }
  40% { transform: translateX(6px); }
  60% { transform: translateX(-4px); }
  80% { transform: translateX(4px); }
}

.fab { position: relative; display: flex; flex-direction: column-reverse; align-items: center; gap: 8px; }
.fab-main {
  width: 56px; height: 56px;
  border-radius: 50%;
  background: #B8FB3C;
  display: flex; align-items: center; justify-content: center;
  cursor: pointer;
  box-shadow: 0 4px 24px rgba(184,251,60,0.3);
  transition: transform 0.3s cubic-bezier(0.34,1.56,0.64,1);
  font-size: 22px; color: #0a0a0f;
}
.fab:hover .fab-main { transform: rotate(45deg); }
.fab-action {
  width: 44px; height: 44px;
  border-radius: 50%;
  background: rgba(255,255,255,0.1);
  border: 1px solid rgba(255,255,255,0.15);
  display: flex; align-items: center; justify-content: center;
  cursor: pointer;
  font-size: 16px;
  opacity: 0;
  transform: scale(0.6) translateY(20px);
  transition: all 0.3s cubic-bezier(0.34,1.56,0.64,1);
}
.fab:hover .fab-action { opacity: 1; transform: scale(1) translateY(0); }
.fab:hover .fab-action:nth-child(2) { transition-delay: 0.05s; }
.fab:hover .fab-action:nth-child(3) { transition-delay: 0.1s; }
